const err = $json.error;
const detail = (err && (err.message || err)) || 'file read failed (unknown error)';
return [{ json: { configOk: false, reason_detail: detail } }];

const config = $json.config;
const errors = [];

if (!config || typeof config !== 'object') {
  errors.push('config is not an object');
} else {
  const requiredTop = ['config_version', 'tenant', 'company_identity', 'icp_description', 'scoring_dimensions', 'hard_disqualifiers', 'thresholds', 'email_rules'];
  for (const key of requiredTop) {
    if (config[key] === undefined || config[key] === null) errors.push(`missing required field: ${key}`);
  }

  if (config.company_identity) {
    for (const key of ['name', 'sender_name', 'value_proposition', 'tone']) {
      if (!config.company_identity[key]) errors.push(`missing company_identity.${key}`);
    }
  }

  if (!Array.isArray(config.scoring_dimensions) || config.scoring_dimensions.length === 0) {
    errors.push('scoring_dimensions must be a non-empty array');
  } else {
    let weightSum = 0;
    config.scoring_dimensions.forEach((dim, i) => {
      if (!dim.key) errors.push(`scoring_dimensions[${i}] missing key`);
      if (typeof dim.weight !== 'number') errors.push(`scoring_dimensions[${i}] (${dim.key || i}) missing numeric weight`);
      else weightSum += dim.weight;
      if (!dim.ideal) errors.push(`scoring_dimensions[${i}] (${dim.key || i}) missing ideal`);
    });
    if (weightSum !== 100) errors.push(`scoring_dimensions weights sum to ${weightSum}, must sum to exactly 100`);
  }

  if (!Array.isArray(config.hard_disqualifiers)) {
    errors.push('hard_disqualifiers must be an array');
  }

  if (config.thresholds) {
    const { hot, review, nurture } = config.thresholds;
    if (typeof hot !== 'number' || typeof review !== 'number' || typeof nurture !== 'number') {
      errors.push('thresholds.hot/review/nurture must all be numbers');
    } else if (!(hot > review && review > nurture)) {
      errors.push(`thresholds must be ordered hot > review > nurture, got hot=${hot}, review=${review}, nurture=${nurture}`);
    }
  } else {
    errors.push('missing thresholds');
  }

  if (config.email_rules) {
    for (const key of ['max_words', 'must_reference', 'never', 'cta']) {
      if (config.email_rules[key] === undefined) errors.push(`missing email_rules.${key}`);
    }
  }
}

if (errors.length > 0) {
  return [{ json: { configOk: false, reason_detail: errors.join('; ') } }];
}

return [{ json: { configOk: true, config, config_version: config.config_version } }];
